import React, { Component } from 'react';
import algoliasearch from 'algoliasearch';
import { InstantSearch, SearchBox, Hits, connectHits, connectInfiniteHits, InfiniteHits } from 'react-instantsearch-dom';


import './App.css';


const searchClient = algoliasearch('0HAV8OIN0H', '34a2bb37ce4654ab910fc2fbee812efd');
let index = searchClient.initIndex("Partners");

const infiniteHits = ({ hits, refine }) => {
    console.log(hits[0])
    return (
        <div className="hits">
            {hits.map(hit => (
                <div className="hit" key={hit.objectID}>
                    <h2 className="name">Organization/Business Name: {hit.organization_name}</h2>
                    <h3 className="name">Contact Person: {hit.contact_person}</h3>
                    <p>Contact phone: <a href={"tel:" + hit.contact_number}>{hit.contact_number}</a></p>
                    <p>Contact email: <a href={"mail-to:" + hit.contact_email}>{hit.contact_email}</a></p>
                    <p>Address:
                        <br/>
                        <i>{hit.address.linel}, {hit.address.locality}, {hit.address.state}, {hit.address.postal_code}</i>
                    </p>
                    <p>Website: <a href={hit.website} target="_blank">{hit.website}</a></p>
                    <p>Type of Organization: {hit.type_organisation}</p>
                    <p>Community Offerings: {hit.community}</p>
                </div>
            ))}
            <button className="show-more" onClick={refine}>Show more</button>
        </div>);
}
const CustomInfiniteHits = connectInfiniteHits(infiniteHits);


